	}

	hasPublicIP := false
	for _, ip := range ips {
		if !isPrivateIP(ip) {
			hasPublicIP = true
			break
		}
	}
	if !hasPublicIP {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Private IP addresses are not allowed"})
	}

	// Create HTTP client with SSRF protection
	client := &http.Client{
		Timeout: requestTimeout,
		Transport: &http.Transport{
