// isPrivateHost checks for obviously private hostnames
func isPrivateHost(host string) bool {
	blockedHosts := []string{"localhost", "127.0.0.1", "::1", "0.0.0.0"}
	for _, blocked := range blockedHosts {
		if host == blocked {
