func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && title == "" {
				title = extractTextContent(n)
			}

			// Extract meta description (standard or Open Graph)
			if n.Data == "meta" && description == "" {
				var name, content string
				var isOGDescription bool

				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						if attr.Val == "og:description" {
							isOGDescription = true
						}
					case "content":
						content = attr.Val
					}
				}

				if (strings.EqualFold(name, "description") || isOGDescription) && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Continue traversing if we haven't found both yet
		if title == "" || description == "" {
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				traverse(c)
			}
		}
	}

	traverse(doc)
	return title, description
}

func extractTextContent(n *html.Node) string {
	var text strings.Builder
	var extract func(*html.Node)
	extract = func(n *html.Node) {
		if n.Type == html.TextNode {
			text.WriteString(n.Data)
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extract(c)
		}
	}
	extract(n)
	return strings.TrimSpace(text.String())
