// createSecureHTTPClient creates an HTTP client with SSRF protection and timeouts
func createSecureHTTPClient() *http.Client {
	return &http.Client{
		Timeout: requestTimeout,
		Transport: &http.Transport{
			DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
				// Split host and port
				host, port, err := net.SplitHostPort(addr)
				if err != nil {
					return nil, err
				}

				// Resolve IP addresses
				ips, err := net.LookupIP(host)
				if err != nil {
					return nil, err
				}

				// Try connecting to non-private IPs only
				for _, ip := range ips {
					if isPrivateIP(ip) {
						continue
					}

					dialer := &net.Dialer{
						Timeout:   5 * time.Second,
						KeepAlive: 30 * time.Second,
					}

					ipAddr := net.JoinHostPort(ip.String(), port)
					conn, err := dialer.DialContext(ctx, network, ipAddr)
					if err == nil {
						return conn, nil
					}
				}

				return nil, fmt.Errorf("no public IP addresses available for host")
			},
