// isPrivateURL checks if the URL points to a private/internal IP address
func isPrivateURL(u *url.URL) bool {
	hostname := u.Hostname()

	// Check for localhost variants
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

