					return nil, fmt.Errorf("access to private IP addresses is not allowed")
				}
			}

			// Use a dialer with timeout
			dialer := &net.Dialer{
				Timeout:   3 * time.Second,
				KeepAlive: 30 * time.Second,
			}
			return dialer.DialContext(ctx, network, addr)
		},
	}

	// Create HTTP client with timeout, redirect limit, and custom transport
	client := &http.Client{
		Timeout:   requestTimeout,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Prevent redirect loops
			if len(via) >= 10 {
				return fmt.Errorf("too many redirects")
			}

			// Validate redirect target for SSRF
			if req.URL != nil {
				if isPrivateHost(req.URL.Hostname()) {
					return fmt.Errorf("redirect to private address not allowed")
				}
				if port := req.URL.Port(); port != "" && port != "80" && port != "443" {
					return fmt.Errorf("redirect to non-standard port not allowed")
				}
			}
			return nil
		},
	}

	// Create request with context for cancellation
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")
	httpReq.Header.Set("Accept-Language", "en-US,en;q=0.5")
	httpReq.Header.Set("Accept-Encoding", "identity")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Log the actual error internally but return generic message to prevent information leakage
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit response body size to prevent memory exhaustion
	limitedReader := io.LimitReader(resp.Body, maxResponseSize+1)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	if int64(len(body)) > maxResponseSize {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Response too large"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// isPrivateHost checks if the hostname is a known internal hostname
func isPrivateHost(hostname string) bool {
	lowerHost := strings.ToLower(hostname)

	// Check for localhost variations
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || lowerHost == "0.0.0.0" {
		return true
	}

	// Check for common internal TLDs
	if strings.HasSuffix(lowerHost, ".local") || strings.HasSuffix(lowerHost, ".internal") || 
	   strings.HasSuffix(lowerHost, ".localhost") {
		return true
	}

	// Check if it's a private IP address directly
	if ip := net.ParseIP(hostname); ip != nil {
		return isPrivateIP(ip)
	}

	return false
}

// isPrivateIP checks if the IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for loopback, private ranges, link-local, multicast, etc.
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for CGNAT range (100.64.0.0/10)
	cgnat := net.IPNet{
		IP:   net.ParseIP("100.64.0.0"),
		Mask: net.CIDRMask(10, 32),
	}
	if cgnat.Contains(ip) {
		return true
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && description == "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

