		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("received status code %d", resp.StatusCode)})
	}

	// Limit reading to 1MB to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	title, description := extractMetaInfo(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetaInfo extracts title and meta description from HTML content
func extractMetaInfo(htmlContent string) (title, description string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node) bool
	traverse = func(n *html.Node) bool {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && title == "" {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				// Check for standard description or Open Graph description
				if description == "" && (strings.EqualFold(name, "description") || strings.EqualFold(name, "og:description")) {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Stop traversal if we found both values
		if title != "" && description != "" {
			return true
		}

		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if traverse(c) {
				return true
			}
		}
		return false
	}

	traverse(doc)
	return
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register handler under /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

